using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController(
    PredictionEnginePool<TicketData, TicketPrediction> predictionEnginePool,
    CategoryLabels categoryLabels) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<ClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionEnginePool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < categoryLabels.Labels.Length && i < prediction.Score.Length; i++)
        {
            scores[categoryLabels.Labels[i]] = prediction.Score[i];
        }

        return Ok(new ClassificationResult
        {
            Category = prediction.Category,
            Confidence = prediction.Score.Max(),
            Scores = scores
        });
    }
}

