using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train model at startup and log evaluation metrics
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "ticket-model.zip");

using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    var logger = loggerFactory.CreateLogger("ModelTraining");
    var labels = TicketModelTrainer.TrainAndEvaluate(dataPath, modelPath, logger);
    builder.Services.AddSingleton(new CategoryLabels(labels));
}

// Thread-safe pooled prediction engine for ASP.NET Core
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

